async function runFullSessionCleanup(sessionId, reason) {
  console.log(`[Session Cleanup] Starting full cleanup for ${sessionId}, Reason: ${reason}`);
  const supabase2 = getSupabase();
  const { data: activeMatch } = await supabase2.from("matches").select("id, user_a, user_b, status").or(`user_a.eq.${sessionId},user_b.eq.${sessionId}`).neq("status", "ended").limit(1).maybeSingle();
  if (activeMatch) {
    await supabase2.from("matches").update({ status: "ended", ended_at: (/* @__PURE__ */ new Date()).toISOString(), ended_reason: "disconnect" }).eq("id", activeMatch.id);
    const partnerId = activeMatch.user_a === sessionId ? activeMatch.user_b : activeMatch.user_a;
    if (partnerId) {
      await broadcastToSession(partnerId, "partner_left", {
        reason: "PARTNER_DISCONNECTED"
      }).catch(() => {
      });
      await supabase2.from("visitor_sessions").update({ status: "SEARCHING" }).eq("id", partnerId).neq("status", "TERMINATED");
      const { data: existingQ } = await supabase2.from("waiting_queue").select("id").eq("session_id", partnerId).in("status", ["matched", "left", "expired"]).limit(1).maybeSingle();
      if (existingQ) {
        await supabase2.from("waiting_queue").update({ status: "waiting", last_seen: (/* @__PURE__ */ new Date()).toISOString() }).eq("id", existingQ.id);
      } else {
        await supabase2.from("waiting_queue").insert({
          session_id: partnerId,
          status: "waiting",
          joined_at: (/* @__PURE__ */ new Date()).toISOString(),
          last_seen: (/* @__PURE__ */ new Date()).toISOString()
        });
      }
    }
  }
  await supabase2.from("waiting_queue").update({ status: "left" }).eq("session_id", sessionId).in("status", ["waiting", "matched"]);
  await supabase2.from("visitor_sessions").update({ status: "TERMINATED" }).eq("id", sessionId).neq("status", "TERMINATED");
  await supabase2.from("reservations").delete().or(`session_a.eq.${sessionId},session_b.eq.${sessionId}`);
  console.log(`[Session Cleanup] Complete for ${sessionId}, Reason: ${reason}`);
}
