var NotificationEngine = class {
  static {
    __name(this, "NotificationEngine");
  }
  // Enforces rate limits based on notification category
  static async checkRateLimit(subscriptionId, category) {
    if (category === "critical" || category === "security") return true;
    const supabase2 = getSupabase();
    const timeWindow = category === "campus" ? "7 days" : "1 day";
    const limit = category === "campus" ? 3 : 2;
    const { count: count3 } = await supabase2.from("analytics_events").select("*", { count: "exact", head: true }).eq("event", "NOTIFICATION_SENT").contains("details", { subscriptionId, category }).gte("created_at", new Date(Date.now() - this.parseInterval(timeWindow)).toISOString());
    return (count3 || 0) < limit;
  }
  // Quiet Hours (11 PM to 7 AM local)
  static isQuietHours() {
    const hour = (/* @__PURE__ */ new Date()).getHours();
    return hour >= 23 || hour < 7;
  }
  // Resolve Audience targeting rules
  static async resolveAudience(filters) {
    const supabase2 = getSupabase();
    let query = supabase2.from("user_preferences_cache").select("subscription_id, push_subscriptions!inner(subscription_json, enabled)");
    query = query.eq("push_subscriptions.enabled", true);
    if (filters.campus) query = query.eq("college", filters.campus);
    if (filters.city) query = query.eq("city", filters.city);
    if (filters.state) query = query.eq("state", filters.state);
    if (filters.country) query = query.eq("country", filters.country);
    if (filters.matchMode) query = query.eq("match_mode", filters.matchMode);
    if (filters.interests && filters.interests.length > 0) {
      query = query.contains("interests", filters.interests);
    }
    if (filters.languages && filters.languages.length > 0) {
      query = query.contains("languages", filters.languages);
    }
    const { data } = await query;
    return data || [];
  }
  // Nightly Cleanup
  static async cleanupExpiredSubscriptions() {
    const supabase2 = getSupabase();
    console.log("[NotificationEngine] Cleanup job ready");
  }
  static parseInterval(interval) {
    if (interval === "7 days") return 7 * 24 * 60 * 60 * 1e3;
    return 24 * 60 * 60 * 1e3;
  }
};

// src/notifications/CampaignManager.ts
var CampaignManager = class {
  static {
    __name(this, "CampaignManager");
  }
  static init() {
    const pubKey = process.env.VAPID_PUBLIC_KEY;
    const privKey = process.env.VAPID_PRIVATE_KEY;
    const subject = process.env.VAPID_SUBJECT || "mailto:admin@kaboom-tv.com";
    if (pubKey && privKey) {
      import_web_push.default.setVapidDetails(
        subject,
        pubKey,
        privKey
      );
      console.log("[CampaignManager] Web Push initialized successfully.");
    } else {
      console.warn("[CampaignManager] Missing VAPID_PUBLIC_KEY or VAPID_PRIVATE_KEY. Push notifications will not work.");
    }
  }
  // Broadcast to audience
  static async executeBroadcast(campaignId, title2, body, deepLink, audienceSegments) {
    const targetAudience = await NotificationEngine.resolveAudience(audienceSegments);
    if (!targetAudience.length) return { sent: 0, failed: 0 };
    let sentCount = 0;
    let failedCount = 0;
    const supabase2 = getSupabase();
    const promises = targetAudience.map(async (user) => {
      const subJSON = user.push_subscriptions.subscription_json;
      try {
        await import_web_push.default.sendNotification(
          subJSON,
          JSON.stringify({ title: title2, body, url: deepLink, campaignId })
        );
        sentCount++;
        await supabase2.from("analytics_events").insert({
          event_type: "NOTIFICATION_SENT",
          session_id: user.subscription_id,
          // We link to subscription id for offline tracking
          payload: { campaignId }
        });
      } catch (err) {
        failedCount++;
        if (err.statusCode === 410 || err.statusCode === 404) {
          await supabase2.from("push_subscriptions").update({ enabled: false }).eq("endpoint", subJSON.endpoint);
        }
      }
    });
    await Promise.all(promises);
    return { sent: sentCount, failed: failedCount };
  }
  // Used by the Admin Simulator
  static async sendTestNotification(subscriptionJson, title2, body, deepLink) {
    try {
      await import_web_push.default.sendNotification(
        subscriptionJson,
        JSON.stringify({ title: title2, body, url: deepLink, campaignId: "TEST_CAMPAIGN" })
      );
      return { success: true };
    } catch (err) {
      console.error("Test Push Failed", err);
      return { success: false, error: err.message };
    }
  }
};

